import React, { useState, useEffect } from 'react';

const ENABLE_ADMIN_MODE = true;

const ACHIEVEMENT_QUOTES = [
  {
    quote: 'The best proof of learning is a student who can build, explain, and improve their own work.',
    label: 'Project-first learning',
  },
  {
    quote: 'Confidence grows when students see their ideas become real products, not just assignments.',
    label: 'Student confidence',
  },
  {
    quote: 'Every completed project becomes a portfolio story, a skill signal, and a step toward opportunity.',
    label: 'Career readiness',
  },
];

const REVIEWS = [
  {
    name: 'Priya S.',
    role: 'Final Year CSE Student',
    type: 'Student Review',
    text: 'The project sessions helped me turn theory into a working portfolio. I finally understood how frontend and backend connect.',
  },
  {
    name: 'Kavin R.',
    role: 'Python Workshop Learner',
    type: 'Student Review',
    text: 'Every class had practice, feedback, and small wins. That made coding feel possible instead of confusing.',
  },
  {
    name: 'Nila Academy',
    role: 'Training Partner',
    type: 'Organization Review',
    text: 'Yathirai InfoTech brings structure, patience, and practical outcomes to student technology training.',
  },
  {
    name: 'Arun M.',
    role: 'MERN Stack Learner',
    type: 'Student Review',
    text: 'The mentor guidance made my project presentation sharper and gave me confidence to explain my own code.',
  },
  {
    name: 'Bright Future School',
    role: 'Institution Partner',
    type: 'Organization Review',
    text: 'Students were engaged from the first session because the training was visual, hands-on, and easy to follow.',
  },
  {
    name: 'Meena V.',
    role: 'UI Design Learner',
    type: 'Student Review',
    text: 'I learned how to think about layout, colors, and user experience instead of just copying designs.',
  },
];

const DEFAULT_PHOTOS = [
  {
    id: 1,
    title: 'Full Stack Project Lab',
    kicker: 'MERN Stack',
    imageUrl: 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=1000&h=760&fit=crop',
  },
  {
    id: 2,
    title: 'UI Design Review',
    kicker: 'Design Thinking',
    imageUrl: 'https://images.unsplash.com/photo-1586717791821-3f44a563fa4c?w=800&h=600&fit=crop',
  },
  {
    id: 3,
    title: 'Python Workshop',
    kicker: 'Hands-on Coding',
    imageUrl: 'https://images.unsplash.com/photo-1517694712178-26efb90288f8?w=800&h=600&fit=crop',
  },
  {
    id: 4,
    title: 'Analytics Dashboard',
    kicker: 'Data Skills',
    imageUrl: 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&h=600&fit=crop',
  },
  {
    id: 5,
    title: 'Team Presentation',
    kicker: 'Communication',
    imageUrl: 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&h=600&fit=crop',
  },
  {
    id: 6,
    title: 'Student Recognition',
    kicker: 'Achievement',
    imageUrl: 'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=800&h=600&fit=crop',
  },
];

function PhotoGallery() {
  const [showAddForm, setShowAddForm] = useState(false);
  const [formData, setFormData] = useState({ title: '', imageUrl: '' });
  const [isAdmin, setIsAdmin] = useState(false);
  const [photos, setPhotos] = useState(DEFAULT_PHOTOS);

  useEffect(() => {
    if (ENABLE_ADMIN_MODE) {
      const adminToken = localStorage.getItem('adminToken');
      setIsAdmin(!!adminToken);
    } else {
      setIsAdmin(false);
    }
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleAddPhoto = (e) => {
    e.preventDefault();
    if (formData.title && formData.imageUrl) {
      const newPhoto = {
        id: photos.length + 1,
        title: formData.title,
        kicker: 'New Highlight',
        imageUrl: formData.imageUrl,
      };
      setPhotos([...photos, newPhoto]);
      setFormData({ title: '', imageUrl: '' });
      setShowAddForm(false);
    }
  };

  const handleDeletePhoto = (id) => {
    setPhotos(photos.filter(photo => photo.id !== id));
  };

  const featuredPhoto = photos[0];
  const galleryPhotos = photos.slice(1);

  return (
    <section className="photo-gallery-section">
      <div className="container">
        <div className="gallery-header">
          <p className="gallery-eyebrow">Student Work & Recognition</p>
          <h2>Achievements shaped through real practice</h2>
          <p className="gallery-subtitle">
            A polished look at project learning, guided workshops, teamwork, and the moments where students turn skills into confidence.
          </p>
        </div>

        <div className="achievement-quotes">
          {ACHIEVEMENT_QUOTES.map(item => (
            <figure className="achievement-quote" key={item.label}>
              <blockquote>{item.quote}</blockquote>
              <figcaption>{item.label}</figcaption>
            </figure>
          ))}
        </div>

        <div className="rich-gallery-layout">
          {featuredPhoto && (
            <article className="featured-gallery-card">
              <img src={featuredPhoto.imageUrl} alt={featuredPhoto.title} />
              <div className="gallery-card-overlay">
                <span>{featuredPhoto.kicker}</span>
                <h3>{featuredPhoto.title}</h3>
              </div>
              {isAdmin && (
                <button
                  className="delete-btn"
                  aria-label={`Delete ${featuredPhoto.title}`}
                  onClick={() => handleDeletePhoto(featuredPhoto.id)}
                >
                  x
                </button>
              )}
            </article>
          )}

          <div className="gallery-card-grid">
            {galleryPhotos.map(photo => (
              <article className="gallery-visual-card" key={photo.id}>
                <img src={photo.imageUrl} alt={photo.title} />
                <div className="gallery-card-overlay">
                  <span>{photo.kicker}</span>
                  <h3>{photo.title}</h3>
                </div>
                {isAdmin && (
                  <button
                    className="delete-btn"
                    aria-label={`Delete ${photo.title}`}
                    onClick={() => handleDeletePhoto(photo.id)}
                  >
                    x
                  </button>
                )}
              </article>
            ))}
          </div>
        </div>

        <div className="gallery-proof-strip" aria-label="Achievement summary">
          <div>
            <strong>Project-led</strong>
            <span>Training that ends with visible work</span>
          </div>
          <div>
            <strong>Portfolio-ready</strong>
            <span>Students leave with work they can present</span>
          </div>
          <div>
            <strong>Mentor guided</strong>
            <span>Feedback at every important step</span>
          </div>
        </div>

        <div className="review-slider" aria-label="Student and organization reviews">
          <div className="review-slider-header">
            <span>What learners and partners say</span>
          </div>
          <div className="review-slider-window">
            <div className="review-track">
              {[...REVIEWS, ...REVIEWS].map((review, index) => (
                <article className="review-card" key={`${review.name}-${index}`}>
                  <div className="review-card-top">
                    <span>{review.type}</span>
                    <strong>{review.name}</strong>
                  </div>
                  <p>{review.text}</p>
                  <small>{review.role}</small>
                </article>
              ))}
            </div>
          </div>
        </div>

        <div className="gallery-controls">
          {isAdmin && (
            <button
              className="add-photo-btn"
              onClick={() => setShowAddForm(!showAddForm)}
            >
              Add Photo
            </button>
          )}
        </div>

        {isAdmin && showAddForm && (
          <div className="add-photo-form">
            <h3>Add New Photo</h3>
            <form onSubmit={handleAddPhoto}>
              <input
                type="text"
                name="title"
                placeholder="Photo Title"
                value={formData.title}
                onChange={handleInputChange}
                required
              />
              <input
                type="url"
                name="imageUrl"
                placeholder="Image URL"
                value={formData.imageUrl}
                onChange={handleInputChange}
                required
              />
              <div className="form-buttons">
                <button type="submit" className="submit-btn">
                  Add Photo
                </button>
                <button
                  type="button"
                  className="cancel-btn"
                  onClick={() => setShowAddForm(false)}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        )}
      </div>
    </section>
  );
}

export default PhotoGallery;
